const item = items[0] ?? { json: {}, binary: {} };
const body = item.json?.body ?? {};

// Required fields from multipart form-data
const user_id = (body.user_id || '').toString();
const session_id = (body.session_id || '').toString();
// const question_text = (body.question_text || '').toString();

// question_id can arrive as string
const question_id_raw = body.question_id;
const question_id = typeof question_id_raw === 'number'
  ? question_id_raw
  : parseInt((question_id_raw || '').toString(), 10);

// Find the uploaded audio binary key (prefer "audio")
const binaryKeys = item.binary ? Object.keys(item.binary) : [];
const audioKey = binaryKeys.includes('audio') ? 'audio' : (binaryKeys[0] || null);

// Validation (no auth)
const errors = [];
if (!user_id) errors.push('Missing user_id');
if (!session_id) errors.push('Missing session_id');
// if (!question_text) errors.push('Missing question_text');
if (!Number.isFinite(question_id)) errors.push('Missing/invalid question_id');
if (!audioKey) errors.push('Missing audio file');

return [{
  json: {
    valid: errors.length === 0,
    errors,
    user_id,
    session_id,
    question_id,
    // question_text,
    audioBinaryKey: audioKey,
  },
  binary: item.binary,
}];

const norm = $items('Auth + Normalize Input')[0]?.json || {};
const whisper = $items('Whisper Transcription (OpenAI HTTP)')[0]?.json || {};
const session = items?.[0]?.json || {};

const transcript = String(whisper.text || whisper.transcript || '');

const extracted = session.extracted_data || {};
const questions = Array.isArray(session.questions) ? session.questions : [];

const qid = norm.question_id;

const matched = questions.find(q => String(q.id) === String(qid));

return [{
  json: {
    user_id: norm.user_id || session.user_id || null,
    transcript,
    role_title: extracted.role_title || null,
    seniority: extracted.seniority_level || null,
    skills: extracted.top_5_skills || [],
    question_text: norm.question_text || matched?.question || null,
    ideal_keywords: matched?.ideal_keywords || [],
    session_id: norm.session_id || session.session_id,
    question_id: qid || null,
  }
}];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "score": {
      "type": "integer",
      "minimum": 1,
      "maximum": 10,
      "description": "Rating from 1 to 10"
    },
    "feedback": {
      "type": "string",
      "description": "2-3 sentences evaluating the answer in context of the job requirements"
    },
    "strength": {
      "type": "string",
      "description": "One specific thing the candidate did well"
    },
    "improvement": {
      "type": "string",
      "description": "One actionable suggestion to improve the answer"
    },
    "example_answer": {
      "type": "string",
      "description": "A concise ideal sample answer tailored to the question and job requirements, using best practices like STAR if applicable"
    },
    "keywords_mentioned": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "List of keywords mentioned in the answer"
    },
    "framework_used": {
      "type": "string",
      "enum": ["STAR", "CIRCLES", "None"],
      "description": "Framework used in the answer"
    }
  },
  "required": [
    "score",
    "feedback",
    "strength",
    "improvement",
    "example_answer",
    "keywords_mentioned",
    "framework_used"
  ]
}

